import { collection, addDoc, query, where, getDocs, onSnapshot } from "firebase/firestore";
import { db } from "../firebase";
import { useState, useEffect } from "react";

export default function IssueSelect({ user, setSessionId }) {
  const [skills, setSkills] = useState([]);
  const [issue, setIssue] = useState("");
  const [priority, setPriority] = useState("medium");

  useEffect(() => {
    const unsub = onSnapshot(collection(db, "skills"), snap => {
      const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));
      setSkills(list);
      if (list.length > 0) setIssue(list[0].id);
    });
    return () => unsub();
  }, []);

  const startChat = async () => {
    const q = query(
      collection(db, "users"),
      where("role", "==", "agent"),
      where("skills", "array-contains", issue),
      where("status", "==", "online")
    );

    const snap = await getDocs(q);
    if (snap.empty) {
      alert("No agent available for this issue.");
      return;
    }

    const agent = snap.docs[0];

    const session = await addDoc(collection(db, "sessions"), {
      customerId: user.uid,
      agentId: agent.id,
      issue,
      priority,
      status: "active",
      createdAt: Date.now()
    });

    setSessionId(session.id);
  };

  return (
    <div style={{ padding: 20 }}>
      <h3>Start Support Chat</h3>

      <label>Issue Type:</label><br />
      <select value={issue} onChange={e => setIssue(e.target.value)}>
        {skills.map(s => (
          <option key={s.id} value={s.id}>{s.name}</option>
        ))}
      </select>

      <br /><br />

      <label>Priority:</label><br />
      <select value={priority} onChange={e => setPriority(e.target.value)}>
        <option value="high">High</option>
        <option value="medium">Medium</option>
        <option value="low">Low</option>
      </select>

      <br /><br />
      <button onClick={startChat}>Start Chat</button>
    </div>
  );
}
